def create_database(self, database_name):
    """
    Ensure a database with the given name exists. If it does not exist, create it.

    Args:
        database_name (str): The id/name of the database to ensure exists.

    Raises:
        AirflowBadRequest: If database_name is None or empty.
    """
    if not database_name:
        raise AirflowBadRequest("Database name cannot be None or empty.")

    # Check if the database already exists
    existing_database = list(self.get_conn().QueryDatabases({
        "query": "SELECT * FROM r WHERE r.id=@id",
        "parameters": [
            {"name": "@id", "value": database_name}
        ]
    }))

    # Only create if it does not already exist
    if len(existing_database) == 0:
        self.get_conn().CreateDatabase({"id": database_name})
        return True  # Indicate that a new database was created

    return False  # Indicate that the database already existed
